1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_RATE = 0.1;
3	const CURSED_SURCHARGE_RATE = 0.5;
4	const HIGH_ENCHANTMENT_RATE = 0.3;
5	const HIGH_ENCHANTMENT_THRESHOLD = 5;
6	
7	const BASE_PREMIUM: Record<string, number> = {
8	  sword: 100,
9	  amulet: 60,
10	  staff: 80,
11	  potion: 40,
12	  rune: 25,
13	  moonstone: 25,
14	};
15	
16	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
17	const COMPONENT_BLOCK_SIZE = 3;
18	const COMPONENT_BLOCK_PRICE = 60;
19	
20	interface Item {
21	  type: string;
22	  cursed?: boolean;
23	  enchantment?: number;
24	}
25	
26	interface QuoteStep {
27	  op: "quote";
28	  items: Item[];
29	}
30	
31	interface Scenario {
32	  customer: { yearsWithMHPCO: number };
33	  steps: QuoteStep[];
34	}
35	
36	export function runScenario(input: unknown): unknown {
37	  const scenario = input as Scenario;
38	  const results = scenario.steps.map((step) => {
39	    const countsByType: Record<string, number> = {};
40	    for (const item of step.items) {
41	      countsByType[item.type] = (countsByType[item.type] ?? 0) + 1;
42	    }
43	    let basePremium = 0;
44	    for (const [type, count] of Object.entries(countsByType)) {
45	      if (COMPONENT_TYPES.has(type) && count === COMPONENT_BLOCK_SIZE) {
46	        basePremium += COMPONENT_BLOCK_PRICE;
47	      } else {
48	        const perItem = BASE_PREMIUM[type] ?? 0;
49	        basePremium += perItem * count;
50	      }
51	    }
52	    let itemSurcharges = 0;
53	    for (const item of step.items) {
54	      const itemBase = BASE_PREMIUM[item.type] ?? 0;
55	      if (item.cursed) {
56	        itemSurcharges += itemBase * CURSED_SURCHARGE_RATE;
57	      }
58	      if ((item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD) {
59	        itemSurcharges += itemBase * HIGH_ENCHANTMENT_RATE;
60	      }
61	    }
62	    const firstInsurance = basePremium * FIRST_INSURANCE_RATE;
63	    const rawPremium = basePremium + itemSurcharges + firstInsurance + PROCESSING_FEE;
64	    const premium = Math.ceil(rawPremium);
65	    return { premium };
66	  });
67	  return { results };
68	}
